Create File From Text.code:
// Create a new file from a string of text.
create(
  // 1) File body (text or binary buffer).
  `Report generated on ${new Date().toISOString()}\n\n${$.data.body}`,
  // 2) File name (extension determines the default mime type).
  'report.txt'
);

Create Folder.code:
// Create an empty folder.
// Pass `null` for content and the folder mime type via options.
create(null, 'My new folder', {
  mimeType: 'application/vnd.google-apps.folder',
});

Upload File.code:
// Upload a file's contents to Drive.
// `content` can be a string or a Buffer; the file name carries the extension.
create(
  $.data.fileContent,
  $.data.fileName,
  {
    // Optional parent folder id.
    parents: [$.configuration.parentFolderId],
    // Optional mime type override.
    mimeType: 'text/csv',
  }
);

Find a File.code:
// Search for files by name. `list` returns matching items on state.data.
list(
  // 1) Folder id to scope the search to (or null to search the whole Drive).
  $.configuration.parentFolderId,
  // 2) Drive list query options.
  {
    // Drive query syntax: https://developers.google.com/drive/api/guides/search-files
    q: `name = '${$.data.fileName}' and trashed = false`,
    fields: 'files(id,name,mimeType,modifiedTime)',
  }
);

Find a Folder.code:
// Search for folders by name.
list(null, {
  q: `mimeType = 'application/vnd.google-apps.folder' and name = '${$.data.folderName}' and trashed = false`,
  fields: 'files(id,name)',
});

Retrieve Files.code:
// List files inside a folder.
list(
  $.configuration.parentFolderId,
  {
    fields: 'files(id,name,mimeType,modifiedTime)',
    pageSize: 100,
  }
);
